--道具购买月卡
function LxMonthCardHandler:MonthlyCardBuyReq(refId,rechargeId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MonthlyCardBuyReq)
    proto.refId = refId
    proto.rechargeId = rechargeId
    SendMessage(LxProtoIds.MonthlyCardBuyReq,proto)
end
--领取月卡奖励
function LxMonthCardHandler:MonthlyCardRewardReq(refId)
    local proto = LxProtoHelper.CreateProto(LxProtoIds.MonthlyCardRewardReq)
    proto.refId = refId
    SendMessage(LxProtoIds.MonthlyCardRewardReq,proto)
end
function LxMonthCardHandler:OnMonthlyCardBuyResp(pb)
    ModuleCenter.MonthCard:SetCardObj(pb.cardObj)
    local itemList = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.BuyMonthCard, itemList)
    FireEvent(EventNames.REFRESH_MONTHCARD)
end
function LxMonthCardHandler:OnMonthlyCardRewardResp(pb)
    ModuleCenter.MonthCard:SetCardObj(pb.cardObj)
    local itemList = ModuleCenter.Common:NewThingsInfo(pb.thingsInfo)
    FireEvent(EventNames.REWARDS_RECEIVED, RewardRecvType.ReceiveMonthCard, itemList)
    FireEvent(EventNames.REFRESH_MONTHCARD)
end
